const SEED_CARPARK_IDS: ReadonlySet<string> = new Set(SEED_CARPARKS.map((c) => c.id));

/** Client-side whitelist check -- used for share-link validation (Security). */
export function isKnownCarparkId(id: string): boolean {
  return SEED_CARPARK_IDS.has(id);
}

export function getSeedCarparkById(id: string): SeedCarpark | undefined {
  return SEED_CARPARKS.find((c) => c.id === id);
}

/**
 * Live-filter-as-you-type search against the static list (Design Details). Matches
 * against BOTH `name` (the raw LTA name, in case a user knows the official name) and
 * `displayName` (what they actually see rendered, per carpark card) -- not just one --
 * so a search never misses a carpark just because the user typed the "other" name for it.
 */
export function searchSeedCarparks(query: string): SeedCarpark[] {
  const normalized = query.trim().toLowerCase();
  if (normalized === "") return [];
  return SEED_CARPARKS.filter(
    (c) =>
      c.name.toLowerCase().includes(normalized) ||
      c.displayName.toLowerCase().includes(normalized),
  );
}
